def maxSumSubsequence(arr, n, k):
    # Create a list to store the maximum sum of subsequence ending at index i
    dp = [0]*n

    # Initialize the first element as 1 (sum of itself)
    dp[0] = arr[0]

    # Fill rest of the table in bottom-up manner
    for i in range(1, n):
        dp[i] = max(dp[i-1], arr[i] + dp[k-2])

    return max(dp[n-1], arr[k-1] + dp[k-2])

