def count_sequences(n):
    def is_valid(seq):
        return sum(seq[:n]) == sum(seq[n:2*n])

    count = 0
    for i in range(1 << (2 * n)):
        seq = [int(b) for b in bin(i)[2:].zfill(2 * n)]
        if is_valid(seq):
            count += 1
    return count

